  { url: 'https://news.google.com/rss/search?q=apertura+tienda+OR+cierre+comercio+OR+nueva+franquicia+OR+competencia+retail+OR+centro+comercial+OR+promocion+descuento+comercio&hl=es&gl=ES&ceid=ES:es', name: 'Google News Competencia', type: 'competition' },
  { url: 'https://news.google.com/rss/search?q=oferta+empleo+comercio+OR+hosteleria+OR+tendencia+consumo+OR+habitos+compra+OR+ecommerce+tienda+fisica&hl=es&gl=ES&ceid=ES:es', name: 'Google News Tendencias', type: 'trends' }
];

const results = await Promise.all(feeds.map(async (feed) => {
  try {
    const resp = await fetch(feed.url, { signal: AbortSignal.timeout(15000) });
    return { ...feed, text: await resp.text(), ok: true };
  } catch (e) {
    console.log(`[Fetch] ${feed.name}: ${e.message}`);
    return { ...feed, text: '', ok: false, error: e.message };
  }
}));

let energyHtml = '';
try {
  const eresp = await fetch('https://www.esios.ree.es/es/pvpc', { signal: AbortSignal.timeout(15000) });
  energyHtml = await eresp.text();
} catch (e) { console.log(`[Energy] ESIOS: ${e.message}`); }

const byType = (t) => results.filter(r => r.type === t);
const textOf = (name) => results.find(r => r.name === name)?.text || '';

return [{ json: {
  newsXml: byType('news').map(r => r.text).join('\n'),
  boeXml: textOf('BOE Ayudas'),
  retailNewsXml: textOf('Google News Retail'),
  ineIpc: textOf('INE IPC'),
  ineRetailSales: textOf('INE Retail Sales'),
  energyHtml,
  mapaXml: textOf('MAPA Alimentación'),
  facuaXml: textOf('FACUA Consumo'),
  priceNewsXml: textOf('Google News Precios'),
  competitionXml: textOf('Google News Competencia'),
  trendsXml: textOf('Google News Tendencias'),
  feedStatus: results.map(r => ({ name: r.name, type: r.type, ok: r.ok, error: r.error || null }))
} }];

const usersResp = $('List Active Users').first().json;
if (!usersResp.ok || !Array.isArray(usersResp.users) || usersResp.users.length === 0) {
  return [{ json: { _skip: true, reason: 'No users after filter', count: 0 } }];
}
return usersResp.users.map(u => ({
  json: {
    user_id: u.user_id || u.id,
    business_name: u.business_name || '',
    business_type: u.business_type || '',
    city: u.city || '',
    sector: u.sector || 'comercio_local'
  }
}));

const shared = $('Fetch Shared Sources').first().json;
const items = $input.all();
const outputs = [];
const TODAY = new Date();
const TODAY_ISO = TODAY.toISOString().split('T')[0];
const MONTH = TODAY.getMonth();
const DOW = TODAY.getDay();

// ── UTILS ──────────────────────────────────────────────────
function parseRSS(xml) {
  const out = [];
  const rx = /<item[^>]*>([\s\S]*?)<\/item>/gi;
  let m;
  while ((m = rx.exec(xml || '')) !== null) {
    const b = m[1];
    const title = (b.match(/<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/s) || [])[1] || '';
    const link = (b.match(/<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/s) || [])[1] || '';
    const desc = (b.match(/<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s) || [])[1] || '';
    const pubDate = (b.match(/<pubDate[^>]*>(.*?)<\/pubDate>/s) || [])[1] || '';
    out.push({ title: title.trim(), link: link.trim(), desc: desc.trim(), pubDate: pubDate.trim() });
  }
  return out;
}

function strip(s = '') {
  return String(s).replace(/<[^>]*>/g, ' ').replace(/&[a-z]+;/gi, ' ').replace(/\s+/g, ' ').trim();
}

function safeIsoDate(raw) {
  try { return raw ? new Date(raw).toISOString().split('T')[0] : TODAY_ISO; }
  catch { return TODAY_ISO; }
}

function normalizeKey(v) {
  return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
}

function iso(d) { return d.toISOString().split('T')[0]; }
function addDays(d, n) { return new Date(d.getTime() + n * 86400000); }
function b64id(s) { return Buffer.from(s || 'x').toString('base64').slice(0, 12); }

// ── KEYWORDS ───────────────────────────────────────────────
function buildKeywordSet(config) {
  const base = [
    'comercio local','pyme','autonomo','autónomo','hosteleria','hostelería',
    'subvencion','subvención','digitalizacion','digitalización','kit digital',
    'iva','energia','energía','alquiler','empleo','consumo','proveedores',
    'margen','beneficio','coste','precio','facturacion','facturación','venta'
  ];
  const dynamic = [
    ...(config.keywords || []),
    ...(config.rss_filter_hints || []),
    config.business_type,
    config.city
  ].filter(Boolean);
  return [...new Set([...base, ...dynamic].map(normalizeKey).filter(Boolean))];
}

function scoreText(text, keywords) {
  const normalized = normalizeKey(text);
  let score = 0;
  for (const kw of keywords) {
    if (normalized.includes(kw)) score += kw.length > 8 ? 4 : 2;
  }
  return Math.min(score, 10);
}

// ── PARSE NEWS ─────────────────────────────────────────────
function parseNews(config) {
  const keywords = buildKeywordSet(config);
  return parseRSS(shared.newsXml || '').map(item => {
    const src = item.link.includes('elpais') ? 'El País' :
                item.link.includes('europapress') ? 'Europa Press' :
                item.link.includes('cincodias') ? 'Cinco Días' : 'Prensa';
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return {
      id: 'news_' + b64id(item.link || item.title),
      title: strip(item.title), summary: strip(item.desc).slice(0, 320),
      source: src, url: item.link, date: safeIsoDate(item.pubDate),
      category: 'noticias', relevance,
      tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8)
    };
  }).filter(n => n.relevance >= 3).sort((a, b) => b.relevance - a.relevance).slice(0, 15);
}

function parseRetailNews(config, xml) {
  const keywords = buildKeywordSet(config);
  return parseRSS(xml || '').map(item => {
    const relevance = scoreText(`${item.title} ${item.desc}`, keywords);
    return {
      id: 'retail_' + b64id(item.link || item.title),
      title: strip(item.title), summary: strip(item.desc).slice(0, 320),
      source: 'Google News Retail', url: item.link, date: safeIsoDate(item.pubDate),
      category: 'retail', relevance,
      tags: keywords.filter(kw => normalizeKey(`${item.title} ${item.desc}`).includes(kw)).slice(0, 8)
    };
  }).filter(n => n.relevance >= 2).sort((a, b) => b.relevance - a.relevance).slice(0, 10);
}

// ── PARSE BOE ──────────────────────────────────────────────
function parseBoe(config) {
  const keywords = buildKeywordSet(config);
  const boeItems = parseRSS(shared.boeXml || '');
  const subsidies = [], regulations = [];
  for (const item of boeItems) {
    const text = `${item.title} ${item.desc}`;
    const normalized = normalizeKey(text);
    if (!keywords.some(kw => normalized.includes(kw))) continue;
    const common = { id: b64id(item.link || item.title), title: strip(item.title), summary: strip(item.desc).slice(0, 300), url: item.link };
    if (/(ley|reglamento|obligacion|obligación|normativa|sancion|sanción)/i.test(text)) {
      regulations.push({ id: `reg_${common.id}`, title: common.title, type: 'normativa', summary: common.summary, url: common.url, impact: /(obligacion|obligación|sancion|sanción)/i.test(text) ? 'high' : 'medium', action_required: 'Revisar requisitos, plazos y adaptación operativa' });
    } else {
      subsidies.push({ id: `sub_${common.id}`, title: common.title, type: /formacion|formación/i.test(text) ? 'formación' : /subvencion|subvención/i.test(text) ? 'subvención' : 'ayuda', amount_range: '', deadline: '', target: 'Pymes y autónomos', url: common.url, status: 'abierta' });
    }
  }
  return { subsidies: subsidies.slice(0, 10), regulations: regulations.slice(0, 10) };
}

// ── INE / ENERGY ───────────────────────────────────────────
function processIneData(shared) {
  const signals = [];
  const fecha = new Date().toISOString();
  function parseIneSeries(data, label) {
    if (!Array.isArray(data)) return;
    for (const serie of data.slice(0, 15)) {
      const nombre = (serie.Nombre || '').replace(/<[^>]*>/g, '').trim();
      const datos = serie.Data || [];
      if (!nombre || datos.length === 0) continue;
      const ultimo = datos[0].Valor;
      const penultimo = datos.length > 1 ? datos[1].Valor : null;
      const variacion = (ultimo != null && penultimo != null && penultimo !== 0)
        ? ((ultimo - penultimo) / penultimo * 100).toFixed(2) : '0';
      signals.push({ name: nombre.substring(0, 150), value: ultimo, previous_value: penultimo, variation_pct: parseFloat(variacion), unit: 'index', source: label, description: `${nombre} — Var: ${variacion}%`, captured_at: fecha });
    }
  }
  try { parseIneSeries(typeof shared.ineIpc === 'string' ? JSON.parse(shared.ineIpc) : shared.ineIpc, 'INE-IPC'); } catch {}
  try { parseIneSeries(typeof shared.ineRetailSales === 'string' ? JSON.parse(shared.ineRetailSales) : shared.ineRetailSales, 'INE-Ventas-Retail'); } catch {}
  return signals;
}

function processEnergy(shared) {
  const html = shared.energyHtml || '';
  const signals = [];
  const fecha = new Date().toISOString();
  const precioMatch = html.match(/(?:precio medio|media)[^0-9]{0,80}?(\d{1,4}[.,]\d{1,4})\s*(?:€\/(?:MWh|kWh)|cts)/i) || html.match(/(\d{1,3}[.,]\d{2,4})\s*€\/MWh/i);
  if (precioMatch) {
    signals.push({ name: 'electricidad_pvpc_media', value: parseFloat(precioMatch[1].replace(',', '.')), unit: 'EUR/MWh', source: 'ESIOS-REE', description: 'Precio medio PVPC electricidad hoy', captured_at: fecha });
  }
  return signals;
}

// ── RETAIL PRICE RADAR (enhanced) ──────────────────────────
function buildRetailPriceRadar(config, shared) {
  const keywords = buildKeywordSet(config);
  const priceKw = [...new Set([...keywords, ...['precio', 'coste', 'proveedor', 'mayorista', 'margen', 'inflacion', 'iva', 'tarifa', 'materia prima', 'logistica', 'transporte', 'alquiler', 'envase', 'embalaje', 'suministro', 'distribucion'].map(normalizeKey)])];
  const signals = [];

  function processFeed(xml, sourceName, defaultType) {
    for (const item of parseRSS(xml || '').slice(0, 12)) {
      const text = `${item.title} ${item.desc}`;
      const score = scoreText(text, priceKw);
      if (score < 2) continue;
      const ntext = normalizeKey(text);
      let type = defaultType;
      if (/(proveedor|mayorista|suministro|distribucion|logistica|transporte)/.test(ntext)) type = 'supply_chain';
      else if (/(precio|coste|tarifa|inflacion|iva|margen)/.test(ntext)) type = 'price_intelligence';
      else if (/(fraude|alerta|retirada|sancion|denuncia)/.test(ntext)) type = 'consumer_alert';
      else if (/(tendencia|habito|consumo|demanda|estacional)/.test(ntext)) type = 'demand_signal';
      signals.push({
        id: `pr_${b64id(item.link || item.title)}`,
        title: strip(item.title).slice(0, 200),
        summary: strip(item.desc).slice(0, 300),
        source: sourceName, url: item.link, type,
        relevance: score,
        impact: score >= 6 ? 'high' : score >= 4 ? 'medium' : 'low',
        date: safeIsoDate(item.pubDate),
        action_hint: type === 'price_intelligence' ? 'Revisar impacto en tu escandallo y márgenes'
          : type === 'supply_chain' ? 'Contactar proveedor o buscar alternativa'
          : type === 'consumer_alert' ? 'Verificar si afecta a tu negocio'
          : type === 'demand_signal' ? 'Ajustar stock u oferta según tendencia'
          : 'Evaluar relevancia para tu negocio'
      });
    }
  }

  processFeed(shared.mapaXml, 'MAPA-Alimentación', 'supply_chain');
  processFeed(shared.facuaXml, 'FACUA-Consumo', 'consumer_alert');
  processFeed(shared.priceNewsXml, 'Prensa-Precios', 'price_intelligence');
  return signals.sort((a, b) => b.relevance - a.relevance).slice(0, 20);
}

// ── COMPETITIVE INTELLIGENCE (NEW) ────────────────────────
function buildCompetitiveIntel(config, shared) {
  const city = normalizeKey(config.city || '');
  const bt = normalizeKey(config.business_type || '');
  const compKw = [...new Set([city, bt, 'apertura', 'cierre', 'franquicia', 'expansion', 'centro comercial', 'promocion', 'descuento', 'oferta', 'competencia', 'tienda online', 'ecommerce'].filter(Boolean))];
  const trendKw = [...new Set([city, bt, 'tendencia', 'consumo', 'habito', 'compra', 'demanda', 'estacional', 'empleo comercio', 'hosteleria', 'turismo'].filter(Boolean))];
  const signals = [];

  for (const item of parseRSS(shared.competitionXml || '').slice(0, 15)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, compKw);
    if (score < 2) continue;
    const ntext = normalizeKey(text);
    let type = 'competitor_move';
    if (/(apertura|nueva|inaugur|franquicia|expansion)/.test(ntext)) type = 'new_competitor';
    else if (/(cierre|liquida|quiebra|traspaso)/.test(ntext)) type = 'competitor_exit';
    else if (/(promocion|descuento|oferta|rebaja|2x1|outlet)/.test(ntext)) type = 'competitor_promo';
    else if (/(centro comercial|gran superficie|marketplace|amazon)/.test(ntext)) type = 'big_retail_move';
    const isLocal = city && ntext.includes(city);
    signals.push({
      id: `comp_${b64id(item.link || item.title)}`,
      title: strip(item.title).slice(0, 200),
      summary: strip(item.desc).slice(0, 300),
      source: 'Inteligencia-Competitiva', url: item.link, type,
      is_local: isLocal,
      relevance: isLocal ? Math.min(score + 3, 10) : score,
      date: safeIsoDate(item.pubDate),
      recommendation: type === 'new_competitor' ? 'Refuerza tu diferenciación y comunicación local'
        : type === 'competitor_exit' ? 'Oportunidad: capta sus clientes con campaña dirigida'
        : type === 'competitor_promo' ? 'Evalúa contraoferta o enfatiza tu valor añadido'
        : type === 'big_retail_move' ? 'Diferénciate en cercanía, servicio personalizado y confianza'
        : 'Monitorizar y evaluar impacto en tu zona'
    });
  }

  for (const item of parseRSS(shared.trendsXml || '').slice(0, 10)) {
    const text = `${item.title} ${item.desc}`;
    const score = scoreText(text, trendKw);
    if (score < 2) continue;
    signals.push({
      id: `trend_${b64id(item.link || item.title)}`,
      title: strip(item.title).slice(0, 200),
      summary: strip(item.desc).slice(0, 300),
      source: 'Tendencias-Consumo', url: item.link, type: 'consumer_trend',
      is_local: city ? normalizeKey(text).includes(city) : false,
      relevance: score,
      date: safeIsoDate(item.pubDate),
      recommendation: 'Adapta tu oferta o comunicación a esta tendencia'
    });
  }

  return signals.sort((a, b) => b.relevance - a.relevance).slice(0, 15);
}

// ── COST MONITOR (NEW) ────────────────────────────────────
function buildCostMonitor(config, ineSignals, energySignals, priceRadar) {
  const bt = normalizeKey(config.business_type || '');
  const alerts = [];
  const recommendations = [];

  // Energy impact
  for (const s of energySignals) {
    if (s.value > 100) {
      alerts.push({ category: 'energia', severity: 'high', title: `Electricidad cara: ${s.value} ${s.unit}`, recommendation: 'Concentrar uso intensivo en horas valle. Revisar contrato eléctrico. Considerar iluminación LED si no la tienes.' });
    } else if (s.value > 60) {
      alerts.push({ category: 'energia', severity: 'medium', title: `Electricidad moderada: ${s.value} ${s.unit}`, recommendation: 'Buen momento para operaciones intensivas en energía.' });
    }
  }

  // IPC impact by business type
  const foodTypes = ['bar', 'cafeteria', 'restaurante', 'panaderia', 'fruteria', 'carniceria', 'supermercado', 'alimentacion'];
  const isFoodBiz = foodTypes.some(t => bt.includes(normalizeKey(t)));
  for (const s of ineSignals) {
    const n = normalizeKey(s.name);
    if (Math.abs(s.variation_pct) < 0.5) continue;
    const rising = s.variation_pct > 0;
    if (isFoodBiz && /(aliment|bebida|pan|carne|pescado|fruta|verdura|aceite|leche|huevo)/.test(n)) {
      alerts.push({
        category: 'costes_producto', severity: Math.abs(s.variation_pct) > 2 ? 'high' : 'medium',
        title: `${s.name}: ${rising ? '+' : ''}${s.variation_pct}%`,
        recommendation: rising
          ? 'Revisar precios de venta o buscar proveedor alternativo. Considerar ajuste de carta/menú.'
          : 'Oportunidad para mejorar margen o hacer promoción con mejor coste.'
      });
    }
    if (/(alquiler|vivienda)/.test(n) && Math.abs(s.variation_pct) > 1) {
      alerts.push({ category: 'costes_local', severity: 'medium', title: `Alquileres: ${rising ? '+' : ''}${s.variation_pct}%`, recommendation: rising ? 'Si se acerca renovación de contrato, negociar con datos.' : 'Buen momento para renegociar o buscar local.' });
    }
    if (/(transporte|combustible|carburante)/.test(n) && Math.abs(s.variation_pct) > 1) {
      alerts.push({ category: 'costes_logistica', severity: Math.abs(s.variation_pct) > 3 ? 'high' : 'medium', title: `Transporte/combustible: ${rising ? '+' : ''}${s.variation_pct}%`, recommendation: rising ? 'Agrupar pedidos a proveedor. Revisar costes de reparto.' : 'Buen momento para stockar o negociar envíos.' });
    }
  }

  // Supply chain alerts from price radar
  for (const s of priceRadar.filter(s => s.impact === 'high')) {
    alerts.push({ category: 'proveedor', severity: 'high', title: s.title.slice(0, 120), recommendation: s.action_hint || 'Revisar impacto en tu cadena de suministro.' });
  }

  // General margin recommendations
  if (alerts.filter(a => a.severity === 'high').length >= 2) {
    recommendations.push({ priority: 'high', action: 'Revisión urgente de escandallos y márgenes', detail: 'Hay varias alertas de costes altos simultáneas. Prioriza los productos con menor margen.', category: 'proteger_margen' });
  }
  if (alerts.some(a => a.category === 'energia' && a.severity === 'high')) {
    recommendations.push({ priority: 'high', action: 'Optimizar consumo energético', detail: 'Electricidad cara hoy. Evita encender hornos/climatización en horas punta si es posible.', category: 'reducir_costes' });
  }
  if (alerts.some(a => a.severity !== 'high' && a.recommendation.includes('Oportunidad'))) {
    recommendations.push({ priority: 'medium', action: 'Aprovechar bajada de costes', detail: 'Algunos costes están bajando. Buen momento para stockar, mejorar margen o lanzar promoción.', category: 'oportunidad' });
  }

  return { alerts: alerts.slice(0, 15), recommendations: recommendations.slice(0, 8), summary: alerts.length === 0 ? 'Sin alertas de costes relevantes hoy.' : `${alerts.filter(a => a.severity === 'high').length} alerta(s) de coste alto, ${alerts.filter(a => a.severity === 'medium').length} media(s).` };
}

// ── BUSINESS RECOMMENDATIONS (NEW) ────────────────────────
function buildBusinessRecommendations(config, context) {
  const recs = [];
  const bizName = config.business_name || 'Tu negocio';
  const bt = normalizeKey(config.business_type || '');

  // Revenue opportunities
  if ((context.calendar.free_slots || []).length > 2) {
    recs.push({ category: 'vender_mas', priority: 'high', title: 'Activar huecos libres', action: `Tienes ${context.calendar.free_slots.length} huecos libres. Lanza oferta flash por WhatsApp a clientes recurrentes.`, estimated_impact: 'Potencial +5-15% facturación día', timeframe: 'hoy' });
  }
  if ((context.competitive.signals || []).some(s => s.type === 'competitor_exit')) {
    recs.push({ category: 'vender_mas', priority: 'high', title: 'Captar clientes de competidor que cierra', action: 'Un competidor cercano ha cerrado o traspasado. Lanza campaña para captar sus clientes.', estimated_impact: 'Potencial +10-20% nuevos clientes', timeframe: 'esta semana' });
  }
  if ((context.competitive.signals || []).some(s => s.type === 'competitor_promo')) {
    recs.push({ category: 'proteger_margen', priority: 'medium', title: 'Competidor con promoción activa', action: 'No bajes precios automáticamente. Enfatiza tu diferenciación: servicio, calidad, cercanía, confianza.', estimated_impact: 'Protección de margen', timeframe: 'esta semana' });
  }

  // Cost protection
  if ((context.cost_monitor.alerts || []).filter(a => a.severity === 'high').length > 0) {
    recs.push({ category: 'proteger_margen', priority: 'high', title: 'Revisar precios de venta', action: 'Costes subiendo. Revisa tu escandallo y ajusta precios donde sea posible sin perder clientes.', estimated_impact: 'Protección de margen 2-5%', timeframe: 'esta semana' });
  }

  // Reputation
  const urgentReviews = context.reputation.reviews?.urgent?.length || 0;
  if (urgentReviews > 0) {
    recs.push({ category: 'proteger_reputacion', priority: 'high', title: `${urgentReviews} reseña(s) negativa(s) sin responder`, action: 'Responde hoy con profesionalidad. Ofrece solución concreta. Una buena respuesta mejora la percepción de futuros clientes.', estimated_impact: 'Protección de reputación online', timeframe: 'hoy' });
  }

  // Subsidies
  if ((context.radar.subsidies || []).length > 0) {
