// ── DAILY SUMMARY (business-focused) ──────────────────────
function buildDailySummary(config, context) {
  const bizName = config.business_name || 'Tu negocio';
  const highTasks = (context.tasks || []).filter(t => t.priority === 'high');
  const medTasks = (context.tasks || []).filter(t => t.priority === 'medium');
  const costAlerts = (context.cost_monitor?.alerts || []).filter(a => a.severity === 'high').length;
  const compMoves = (context.competitive?.signals || []).filter(s => s.relevance >= 5).length;
  const opportunities = (context.radar.subsidies?.length || 0) + (context.competitive?.signals || []).filter(s => s.type === 'competitor_exit').length;
  const risks = (context.radar.regulations?.length || 0) + costAlerts + (context.reputation.reviews?.urgent?.length || 0);
  const totalTasks = (context.tasks || []).length;

  // Business health score
  let score = 60;
  score += Math.min((context.radar.news?.length || 0) * 1, 8);
  score += Math.min((context.radar.subsidies?.length || 0) * 3, 12);
  score += Math.min((context.marketing?.campaigns?.length || 0) * 2, 8);
  score += context.reputation.connected ? 5 : 0;
  score += context.inbox.connected ? 5 : 0;
  score += context.calendar.connected ? 3 : 0;
  score -= Math.min((context.reputation.reviews?.urgent?.length || 0) * 8, 24);
  score -= Math.min((context.radar.regulations?.length || 0) * 4, 16);
  score -= Math.min(costAlerts * 5, 15);
  score -= Math.min((context.inbox.awaiting_reply?.length || 0) * 3, 12);
  score = Math.max(0, Math.min(100, score));

  // Headline — focused on what matters for sales
  let headline = '';
  if (highTasks.length > 0) {
    headline = `${highTasks.length} acción(es) urgente(s) para ${bizName}`;
  } else {
    headline = `${bizName}: día sin urgencias`;
  }
  if (costAlerts > 0) headline += ` | ${costAlerts} alerta(s) de costes`;
  if (compMoves > 0) headline += ` | ${compMoves} movimiento(s) de competencia`;
  if (opportunities > 0) headline += ` | ${opportunities} oportunidad(es)`;
  headline += '.';

  // Top 3 priorities — actionable, not informational
  const top3 = highTasks.slice(0, 3).map(t => ({
    action: t.title,
    why: t.estimated_impact || 'Impacto en negocio',
    category: t.category || 'general'
  }));

  // Priority actions
  const actions = [];
  if (highTasks.length > 0) actions.push(`🔴 ${highTasks.length} tarea(s) de alta prioridad — impacto directo en ventas o margen`);
  if (costAlerts > 0) actions.push(`💰 ${costAlerts} alerta(s) de costes — revisar márgenes`);
  if ((context.reputation.reviews?.urgent || []).length > 0) actions.push(`⭐ ${context.reputation.reviews.urgent.length} reseña(s) negativa(s) — responder hoy`);
  if ((context.inbox.awaiting_reply || []).length > 0) actions.push(`📧 ${context.inbox.awaiting_reply.length} email(s) pendiente(s)`);
  if ((context.radar.regulations || []).length > 0) actions.push(`📋 ${context.radar.regulations.length} cambio(s) normativo(s) — revisar cumplimiento`);
  if ((context.marketing?.campaigns || []).length > 0) actions.push(`📣 ${context.marketing.campaigns.length} campaña(s) sugerida(s) para vender más`);
  if ((context.radar.subsidies || []).length > 0) actions.push(`💶 ${context.radar.subsidies.length} ayuda(s) disponible(s) — solicitar antes de que caduquen`);
  if (medTasks.length > 0) actions.push(`🟡 ${medTasks.length} tarea(s) de prioridad media`);

  // Connected modules status
  const modules_active = [
    context.inbox.connected ? 'Gmail' : null,
    context.calendar.connected ? 'Calendar' : null,
    context.reputation.connected ? 'Reputación' : null,
    context.sheets?.connected ? 'Sheets' : null
  ].filter(Boolean);
  const modules_pending = [
    !context.inbox.connected ? 'Gmail' : null,
    !context.calendar.connected ? 'Calendar' : null,
    !context.reputation.connected ? 'Reputación' : null,
    !context.sheets?.connected ? 'Sheets' : null
  ].filter(Boolean);

  return {
    headline,
    business_health_score: score,
    score_interpretation: score >= 75 ? 'Buen día — ejecuta las acciones sugeridas' : score >= 50 ? 'Día normal — atiende las alertas primero' : 'Día con riesgos — prioriza las tareas urgentes',
    top_priorities: top3,
    priority_actions: actions.slice(0, 10),
    opportunities_count: opportunities,
    risks_count: risks,
    tasks_total: totalTasks,
    tasks_high: highTasks.length,
    tasks_medium: medTasks.length,
    modules_connected: modules_active,
    modules_pending: modules_pending,
    tip: modules_pending.length > 0
      ? `Conecta ${modules_pending.join(', ')} en tu panel ENLAZE para desbloquear más automatización.`
      : 'Todos los módulos conectados. ENLAZE trabaja al máximo para ti.'
  };
}

